import { Table01, TableColumn, statusBadge } from '../';

interface TradeRow extends Record<string, unknown> {
  ticker: string;
  side: string;
  qty: number;
  price: string;
  status: string;
}

const tradeColumns: TableColumn<TradeRow>[] = [
  { key: 'ticker', label: 'Ticker' },
  { key: 'side', label: 'Side' },
  { key: 'qty', label: 'Qty', align: 'right' },
  { key: 'price', label: 'Price', align: 'right' },
  { key: 'status', label: 'Status', render: (v) => statusBadge(String(v)) },
];

const trades: TradeRow[] = [
  { ticker: 'AAPL', side: 'Buy', qty: 500, price: '$182.30', status: 'Filled' },
  { ticker: 'MSFT', side: 'Sell', qty: 200, price: '$378.90', status: 'Pending' },
  { ticker: 'NVDA', side: 'Buy', qty: 100, price: '$875.40', status: 'Settled' },
];

<Table01
  data={trades}
  columns={tradeColumns}
  getRowKey={(row) => row.ticker}
/>

import { TableAction01 } from '../';
import { ColumnDef } from '@tanstack/react-table';

interface HoldingRow {
  ticker: string;
  sector: string;
  weight: string;
  pnl: string;
  cost: string;
}

const holdingColumns: ColumnDef<HoldingRow>[] = [
  { header: 'Ticker', accessorKey: 'ticker', enableSorting: true, meta: { align: 'text-left' } },
  { header: 'Sector', accessorKey: 'sector', enableSorting: true, meta: { align: 'text-left' } },
  { header: 'Weight', accessorKey: 'weight', enableSorting: false, meta: { align: 'text-right' } },
  { header: 'P&L', accessorKey: 'pnl', enableSorting: true, meta: { align: 'text-right' } },
  { header: 'Cost Basis', accessorKey: 'cost', enableSorting: false, meta: { align: 'text-right' } },
];

const holdings: HoldingRow[] = [
  { ticker: 'AAPL', sector: 'Technology', weight: '8.4%', pnl: '+$14,200', cost: '$168,000' },
  { ticker: 'JPM', sector: 'Financials', weight: '5.1%', pnl: '+$3,800', cost: '$92,400' },
  { ticker: 'XOM', sector: 'Energy', weight: '3.8%', pnl: '-$1,100', cost: '$68,200' },
];

<TableAction01<HoldingRow>
  data={holdings}
  columns={holdingColumns}
  initialSortId="pnl"
  initialSortDesc={true}
/>
